const deep = (o) => JSON.parse(JSON.stringify(o));
const totalWeight = (kras) => kras.reduce((a, k) => a + k.kpis.reduce((b, p) => b + Number(p.weightage || 0), 0), 0);
const cgpaToBand = (c) => c >= 4.5 ? 5 : c >= 3.5 ? 4 : c >= 2.5 ? 3 : c >= 1.5 ? 2 : 1;
const rKey = (cid, eid) => `${cid}::${eid}`;
const defaultRecord = (type) => type === "Goal Setting" ? { kras: deep(KRA_TEMPLATE), status: "Draft", note: "" } : { review: {}, stage: "self" };

const mapUserRow = (r) => ({
  id: r.id, name: r.name, employeeId: r.employee_id, email: r.email,
  department: r.department, designation: r.designation, role: r.role,
  reportingManager: r.reporting_manager, reportingManagerId: r.reporting_manager_id,
  reportingManagerEmail: r.reporting_manager_email,
});
const mapCycleRow = (r) => ({
  id: r.id, year: r.year, type: r.type, status: r.status, name: r.name || "",
  start: r.start_date, end: r.end_date, participants: r.participants || [],
});
const mapEmailRow = (r) => ({
  id: r.id, from: r.from, to: r.to, toName: r.to_name,
  subject: r.subject, body: r.body, sentAt: r.sent_at, event: r.event,
});
const cycleWriteFields = (c) => ({
  year: Number(c.year), type: c.type, status: c.status, name: (c.name || "").trim() || null,
  start_date: c.start || null, end_date: c.end || null, participants: c.participants || [],
});
const cycleLabel = (c) => (c.name && c.name.trim()) ? c.name : `${c.type} ${c.year}`;

