function InboxPage({ me, emails, isHR }) {
  const [scope, setScope] = useState("me");
  const mine = emails.filter(e => (e.to || "").toLowerCase() === (me.email || "").toLowerCase());
  const list = isHR && scope === "all" ? emails : mine;
  const fmt = (iso) => { try { return new Date(iso).toLocaleString(); } catch (e) { return ""; } };
  return (
    <div className="space-y-3">
      <Notice icon={Mail}>These are the notification emails the system generates for each cycle action. In this preview they are logged here; connect a mail backend to deliver them to real inboxes.</Notice>
      {isHR && (
        <div className="flex items-center gap-2">
          <button onClick={() => setScope("me")} className={`text-xs font-medium px-3 py-1.5 rounded-lg border ${scope === "me" ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-600 border-slate-200 hover:bg-slate-50"}`}>My notifications ({mine.length})</button>
          <button onClick={() => setScope("all")} className={`text-xs font-medium px-3 py-1.5 rounded-lg border ${scope === "all" ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-600 border-slate-200 hover:bg-slate-50"}`}>All sent ({emails.length})</button>
        </div>
      )}
      {list.length === 0 ? <Notice icon={Mail}>No notifications yet. System emails triggered by cycle actions will appear here.</Notice> : list.map(e => (
        <div key={e.id} className="bg-white rounded-xl border border-slate-200 p-4 space-y-2">
          <div className="flex items-start justify-between gap-2 flex-wrap">
            <div className="flex items-center gap-2 min-w-0"><div className="w-8 h-8 rounded-lg bg-indigo-100 text-indigo-600 flex items-center justify-center shrink-0"><Mail className="w-4 h-4" /></div><p className="font-medium text-slate-800 text-sm">{e.subject}</p></div>
            <span className="text-xs text-slate-400 shrink-0">{fmt(e.sentAt)}</span>
          </div>
          <div className="text-xs text-slate-500">From: {e.from}{isHR && scope === "all" && <> &middot; To: <span className="text-slate-600">{e.toName} &lt;{e.to}&gt;</span></>}</div>
          <pre className="text-sm text-slate-600 whitespace-pre-wrap font-sans bg-slate-50 rounded-lg p-3 border border-slate-100">{e.body}</pre>
        </div>
      ))}
    </div>
  );
}

function ChangePwdModal({ me, onSave, onClose }) {
  const [current, setCurrent]   = useState("");
  const [newPwd,  setNewPwd]    = useState("");
  const [confirm, setConfirm]   = useState("");
  const [showC,   setShowC]     = useState(false);
  const [showN,   setShowN]     = useState(false);
  const [err,     setErr]       = useState("");
  const [done,    setDone]      = useState(false);
  const [saving,  setSaving]    = useState(false);

  const save = async () => {
    setErr("");
    if (!current)                   { setErr("Enter your current password."); return; }
    if (newPwd.length < 6)          { setErr("New password must be at least 6 characters."); return; }
    if (newPwd !== confirm)         { setErr("Passwords do not match."); return; }
    setSaving(true);
    const result = await onSave(current, newPwd);
    setSaving(false);
    if (!result.ok) { setErr(result.error || "Something went wrong."); return; }
    setDone(true);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50">
      <div className="bg-white rounded-2xl shadow-xl max-w-sm w-full p-6 space-y-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2"><KeyRound className="w-5 h-5 text-indigo-500" /><h3 className="font-semibold text-slate-800">Change Password</h3></div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 text-xl leading-none">×</button>
        </div>
        {done ? (
          <div className="space-y-4 text-center">
            <div className="w-12 h-12 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center mx-auto"><CheckCircle2 className="w-6 h-6" /></div>
            <p className="text-sm font-medium text-slate-700">Password updated successfully.</p>
            <button onClick={onClose} className="w-full bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium px-4 py-2.5 rounded-xl">Done</button>
          </div>
        ) : (
          <>
            <div className="space-y-3">
              {[
                { label: "Current password", val: current, set: setCurrent, show: showC, toggle: () => setShowC(s=>!s) },
                { label: "New password",     val: newPwd,  set: setNewPwd,  show: showN, toggle: () => setShowN(s=>!s) },
                { label: "Confirm password", val: confirm, set: setConfirm, show: showN, toggle: null },
              ].map(({ label, val, set, show, toggle }) => (
                <div key={label}>
                  <label className="text-xs font-medium text-slate-500 block mb-1">{label}</label>
                  <div className="relative">
                    <input type={show ? "text" : "password"} value={val} onChange={e => { set(e.target.value); setErr(""); }}
                      className="w-full text-sm border border-slate-200 rounded-lg px-3 py-2.5 pr-10 focus:outline-none focus:ring-2 focus:ring-indigo-200" />
                    {toggle && <button onClick={toggle} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">{show ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}</button>}
                  </div>
                </div>
              ))}
            </div>
            {err && <p className="text-xs text-rose-600 flex items-center gap-1"><AlertCircle className="w-3.5 h-3.5" />{err}</p>}
            <div className="flex gap-2">
              <button onClick={onClose} className="flex-1 border border-slate-200 text-slate-600 text-sm font-medium px-4 py-2.5 rounded-xl hover:bg-slate-50">Cancel</button>
              <button onClick={save} disabled={saving} className={`flex-1 text-sm font-medium px-4 py-2.5 rounded-xl ${saving ? "bg-indigo-400 text-white cursor-not-allowed" : "bg-indigo-600 hover:bg-indigo-700 text-white"}`}>{saving ? "Updating…" : "Update password"}</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ---- App ----
export default function App() {
  const [loaded, setLoaded] = useState(false);
  const [loadError, setLoadError] = useState("");
  const [users, setUsers] = useState([]);
  const [cycles, setCycles] = useState([]);
  const [records, setRecords] = useState({});
  const [emails, setEmails] = useState([]);
  const [emailTemplates, setEmailTemplates] = useState({});
  const [currentUserId, setCurrentUserId] = useState(() => {
    try { return localStorage.getItem("pms:currentUserId") || null; } catch (e) { return null; }
  });
  const [view, setView] = useState("home");
  const [flash, setFlash] = useState("");
  const [flashError, setFlashError] = useState("");
  const [showChangePwd, setShowChangePwd] = useState(false);
  const pendingWrites = useRef({});

  const refetchAll = async () => {
    const [usersRes, cyclesRes, recordsRes, emailsRes, tplRes] = await Promise.all([
      supabase.rpc("list_users"),
      supabase.from("cycles").select("*"),
      supabase.from("records").select("*"),
      supabase.from("emails").select("*").order("sent_at", { ascending: false }),
      supabase.from("email_templates").select("*"),
    ]);
    const firstError = usersRes.error || cyclesRes.error || recordsRes.error || emailsRes.error || tplRes.error;
    if (firstError) throw firstError;
    setUsers((usersRes.data || []).map(mapUserRow));
    setCycles((cyclesRes.data || []).map(mapCycleRow));
    const recMap = {};
    (recordsRes.data || []).forEach(r => { recMap[rKey(r.cycle_id, r.employee_id)] = r.data; });
    setRecords(recMap);
    setEmails((emailsRes.data || []).map(mapEmailRow));
    const tplMap = {};
    (tplRes.data || []).forEach(r => { tplMap[r.key] = { subject: r.subject, body: r.body }; });
    setEmailTemplates(tplMap);
  };

  useEffect(() => {
    (async () => {
      try { await refetchAll(); }
      catch (e) { setLoadError("Couldn't load data. Check your connection and refresh."); }
      finally { setLoaded(true); }
    })();
  }, []);

  useEffect(() => {
    try {
      if (currentUserId) localStorage.setItem("pms:currentUserId", currentUserId);
      else localStorage.removeItem("pms:currentUserId");
    } catch (e) { /* ignore */ }
  }, [currentUserId]);

  const showError = (msg) => { setFlashError(msg); setTimeout(() => setFlashError(""), 3000); };

  const changePassword = async (currentPwd, newPwd) => {
    const { data: ok, error } = await supabase.rpc("change_password", {
      p_employee_id: me.employeeId, p_current_password: currentPwd, p_new_password: newPwd,
    });
    if (error) return { ok: false, error: "Something went wrong. Please try again." };
    if (!ok) return { ok: false, error: "Current password is incorrect." };
    return { ok: true };
  };

  const onSaved = (msg) => { setFlash(msg || "Saved."); setTimeout(() => setFlash(""), 2000); };
  const me = users.find(u => u.employeeId === currentUserId) || null;
  const getRecord = (cycle, eid) => records[rKey(cycle.id, eid)] || defaultRecord(cycle.type);

  const persistRecord = async (cid, eid, next) => {
    const { error } = await supabase.from("records").upsert(
      { cycle_id: cid, employee_id: eid, data: next, updated_at: new Date().toISOString() },
      { onConflict: "cycle_id,employee_id" }
    );
    if (error) showError("Couldn't save — check your connection.");
  };

  const setRecord = (cid, eid, next, opts = {}) => {
    setRecords(rs => ({ ...rs, [rKey(cid, eid)]: next }));
    const key = rKey(cid, eid);
    if (pendingWrites.current[key]) clearTimeout(pendingWrites.current[key]);
    if (opts.immediate) {
      persistRecord(cid, eid, next);
    } else {
      pendingWrites.current[key] = setTimeout(() => persistRecord(cid, eid, next), 600);
    }
  };

  const approvedKRAsFor = (eid, year) => {
    const gc = cycles.find(c => c.type === "Goal Setting" && c.year === year);
    if (!gc) return null;
    const rec = records[rKey(gc.id, eid)];
    return rec && rec.status === "Approved" ? rec.kras : null;
  };

  const editUser = async (oldUser, newData) => {
    const { error } = await supabase.rpc("edit_user", {
      p_id: oldUser.id, p_name: newData.name,
      p_email: newData.email, p_department: newData.department, p_designation: newData.designation,
      p_role: newData.role, p_reporting_manager_id: newData.reportingManagerId,
      p_password: (newData.password || "").trim() ? newData.password : null,
    });
    if (error) {
      showError("Couldn't update user — please retry.");
      return;
    }
    await refetchAll();
    onSaved("User updated.");
  };

  const uploadKRA = async (employeeId, kras, mode = "approved") => {
    const goalCycles = cycles.filter(c => c.type === "Goal Setting" && (c.participants || []).includes(employeeId));
    if (!goalCycles.length) {
      return { ok: false, text: "User is not enrolled in any Goal Setting cycle. Enroll them first via Cycle Management." };
    }
    const next = mode === "draft"
      ? { kras, status: "Draft", note: "KRA sheet prepared by HR — please review and submit." }
      : { kras, status: "Approved", note: "KRA uploaded and approved by HR.", approvedAt: new Date().toISOString() };
    goalCycles.forEach(c => setRecords(rs => ({ ...rs, [rKey(c.id, employeeId)]: next })));
    await Promise.all(goalCycles.map(c => persistRecord(c.id, employeeId, next)));
    const subject = users.find(u => u.employeeId === employeeId);
    if (subject) goalCycles.forEach(c => notify(mode === "draft" ? "kra_draft" : "kra_approved", { cycle: c, subject }));
    onSaved(mode === "draft" ? `KRA saved as draft for ${employeeId}.` : `KRA uploaded & approved for ${employeeId}.`);
    return { ok: true, text: `KRA applied to ${goalCycles.length} Goal Setting cycle${goalCycles.length > 1 ? "s" : ""} — ${mode === "draft" ? "saved as Draft for the employee to review & submit" : "set to Approved"}.` };
  };

  const resetParticipant = async (cycle, employeeId) => {
    const prev = records[rKey(cycle.id, employeeId)];
    let next;
    if (cycle.type === "Goal Setting") {
      // Keep the KRAs that were entered/uploaded; drop back to editable Draft.
      const kras = prev && prev.kras ? prev.kras : deep(KRA_TEMPLATE);
      next = { kras, status: "Draft", note: "" };
    } else {
      // Keep the employee's self-assessment; clear manager/HR parts; back to self stage.
      const prevReview = (prev && prev.review) || {};
      const cleaned = {};
      Object.entries(prevReview).forEach(([k, v]) => {
        if (k === "__returnNote" || k === "__hrNote") return;
        if (k === "__overall") { const { mgrComment, ...selfOverall } = v || {}; cleaned.__overall = selfOverall; return; }
        const { mgrRating, mgrComment, ...selfPart } = v || {};
        cleaned[k] = selfPart;
      });
      next = { review: cleaned, stage: "self" };
    }
    setRecords(rs => ({ ...rs, [rKey(cycle.id, employeeId)]: next }));
    await persistRecord(cycle.id, employeeId, next);
    const subject = users.find(u => u.employeeId === employeeId);
    if (subject) notify("cycle_reset", { cycle, subject });
    onSaved(`Reset ${subject ? subject.name : employeeId}'s cycle.`);
  };

  const tpl = (key) => emailTemplates[key] || EMAIL_TEMPLATE_DEFAULTS[key];
  const emailSignature = () => (emailTemplates.__signature && emailTemplates.__signature.body != null ? emailTemplates.__signature.body : DEFAULT_SIGNATURE);

  const composeEmails = (event, ctx) => {
    const { cycle, subject, note } = ctx || {};
    if (!subject) return [];
    const cy = cycle ? cycleLabel(cycle) : "the cycle";
    const mgrTo = subject.reportingManagerEmail;
    const mgrName = subject.reportingManager;
    const hrUsers = users.filter(u => u.role === "hr");
    const baseVars = { employeeName: subject.name, employeeId: subject.employeeId, cycle: cy, managerName: mgrName, note: note || "" };
    const sig = emailSignature();
    const out = [];
    const emit = (key, to, toName, extraVars) => {
      if (!to || to === "—") return;
      const t = tpl(key); if (!t) return;
      const vars = { ...baseVars, ...(extraVars || {}) };
      out.push({ to, toName, subject: fillTemplate(t.subject, vars), body: fillTemplate(t.body, vars) + sig });
    };
    // Each event maps to one or more template slots + their recipients.
    const routes = {
      enrolled:         [["enrolled_employee", subject.email, subject.name]],
      kra_submitted:    [["kra_submitted_manager", mgrTo, mgrName], ["kra_submitted_employee", subject.email, subject.name]],
      kra_approved:     [["kra_approved_employee", subject.email, subject.name]],
      kra_draft:        [["kra_draft_employee", subject.email, subject.name]],
      kra_changes:      [["kra_changes_employee", subject.email, subject.name]],
      self_submitted:   [["self_submitted_manager", mgrTo, mgrName], ["self_submitted_employee", subject.email, subject.name]],
      midyear_complete: [["midyear_complete_employee", subject.email, subject.name]],
      review_returned:  [["review_returned_employee", subject.email, subject.name]],
      hr_approved:      [["hr_approved_employee", subject.email, subject.name], ["hr_approved_manager", mgrTo, mgrName]],
      hr_rejected:      [["hr_rejected_manager", mgrTo, mgrName]],
      cycle_reset:      [["cycle_reset_employee", subject.email, subject.name]],
    };
    if (event === "review_to_hr") {
      hrUsers.forEach(h => emit("review_to_hr_hr", h.email, h.name, { hrName: h.name }));
      emit("review_to_hr_employee", subject.email, subject.name);
    } else {
      (routes[event] || []).forEach(([key, to, toName]) => emit(key, to, toName));
    }
    return out;
  };

  const notify = (event, ctx) => {
    const built = composeEmails(event, ctx);
    if (!built.length) return;
    const now = Date.now();
    const rows = built.map((e, i) => ({ id: now + i + Math.random(), from: "OCPL PMS <no-reply@ocpl.com>", sentAt: new Date().toISOString(), event, ...e }));
    setEmails(prev => [...rows, ...prev]);
    supabase.from("emails").insert(rows.map(r => ({
      from: r.from, to: r.to, to_name: r.toName, subject: r.subject, body: r.body, event: r.event, sent_at: r.sentAt,
    }))).then(({ error }) => { if (error) console.error("Failed to persist notification email", error); });
    // Fire real email delivery via the send-email Edge Function (no-op until that function is deployed).
    supabase.functions.invoke("send-email", {
      body: { emails: rows.map(r => ({ to: r.to, toName: r.toName, subject: r.subject, body: r.body })) },
    }).catch((err) => console.error("Email delivery failed", err));
  };

  const saveTemplate = async (key, subject, body) => {
    setEmailTemplates(m => ({ ...m, [key]: { subject, body } }));
    const { error } = await supabase.from("email_templates").upsert({ key, subject, body, updated_at: new Date().toISOString() }, { onConflict: "key" });
    if (error) showError("Couldn't save the template — please retry."); else onSaved("Template saved.");
  };
  const resetTemplate = async (key) => {
    setEmailTemplates(m => { const n = { ...m }; delete n[key]; return n; });
    const { error } = await supabase.from("email_templates").delete().eq("key", key);
    if (error) showError("Couldn't reset the template — please retry."); else onSaved("Template reset to default.");
  };

  if (!loaded) return <div className="min-h-screen bg-slate-50" />;
  if (loadError) return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="max-w-sm w-full"><Notice icon={AlertCircle} tone="rose">{loadError}</Notice></div>
    </div>
  );
  if (!me) return <LoginScreen users={users} onLogin={(id) => { setCurrentUserId(id); setView("home"); }} />;

  const myEmailCount = emails.filter(e => (e.to || "").toLowerCase() === (me.email || "").toLowerCase()).length;
  const hasApprovedKRA = cycles.some(c => c.type === "Goal Setting" && (c.participants || []).includes(me.employeeId) && records[rKey(c.id, me.employeeId)]?.status === "Approved");
  const baseTabs = me.role === "hr"
    ? [{ id: "home", label: "Home" }, { id: "cycles", label: "Cycles" }, { id: "approvals", label: "Approvals" }, { id: "users", label: "Users" }, { id: "reports", label: "Reports" }, { id: "templates", label: "Templates" }]
    : me.role === "manager"
      ? [{ id: "home", label: "Home" }, { id: "tasks", label: "My Tasks" }, { id: "team", label: "Team" }, { id: "completed", label: "Completed" }, ...(hasApprovedKRA ? [{ id: "mykra", label: "My KRA" }] : [])]
      : [{ id: "home", label: "Home" }, { id: "tasks", label: "My Tasks" }, { id: "completed", label: "Completed" }, ...(hasApprovedKRA ? [{ id: "mykra", label: "My KRA" }] : [])];
  const tabs = [...baseTabs, { id: "inbox", label: `Inbox${myEmailCount ? ` (${myEmailCount})` : ""}` }];

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <button onClick={() => setView("home")} className="flex items-center shrink-0"><img src={LOGO_STRIP} alt="Brand logos" className="h-8 w-auto object-contain" /></button>
          <nav className="flex items-center gap-1 overflow-x-auto">{tabs.map(t => <button key={t.id} onClick={() => setView(t.id)} className={`text-xs font-medium px-3 py-1.5 rounded-lg whitespace-nowrap transition ${view === t.id ? "bg-indigo-600 text-white" : "text-slate-500 hover:text-slate-800 hover:bg-slate-100"}`}>{t.label}</button>)}</nav>
          <button onClick={() => { setCurrentUserId(null); }} className="text-xs font-medium text-slate-500 hover:text-rose-600 flex items-center gap-1 shrink-0"><LogOut className="w-4 h-4" /> <span className="hidden sm:inline">Sign out</span></button>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 space-y-4">
        <div className="flex items-center justify-between bg-white rounded-xl border border-slate-200 px-4 py-2">
          <span className="text-xs text-slate-500">Signed in as <span className="font-medium text-slate-700">{me.name}</span> ({me.employeeId})</span>
          <div className="flex items-center gap-2"><Pill className={USER_ROLE[me.role].color}>{USER_ROLE[me.role].label}</Pill><button onClick={() => setShowChangePwd(true)} title="Change password" className="p-1.5 rounded-lg text-slate-400 hover:text-indigo-600 hover:bg-slate-100 transition"><KeyRound className="w-3.5 h-3.5" /></button></div>
        </div>
        {flash && <div className="bg-emerald-50 border border-emerald-200 text-emerald-700 text-xs rounded-lg px-3 py-2 flex items-center gap-1"><CheckCircle2 className="w-3.5 h-3.5" /> {flash}</div>}
        {flashError && <div className="bg-rose-50 border border-rose-200 text-rose-700 text-xs rounded-lg px-3 py-2 flex items-center gap-1"><AlertCircle className="w-3.5 h-3.5" /> {flashError}</div>}
        {showChangePwd && <ChangePwdModal me={me} onSave={changePassword} onClose={() => setShowChangePwd(false)} />}

        {view === "home" && <HomeDashboard me={me} cycles={cycles} go={setView} />}
        {view === "tasks" && <MyTasksPage me={me} cycles={cycles} getRecord={getRecord} setRecord={setRecord} onSaved={onSaved} approvedKRAsFor={approvedKRAsFor} notify={notify} />}
        {view === "team" && <TeamPage me={me} users={users} cycles={cycles} getRecord={getRecord} setRecord={setRecord} onSaved={onSaved} approvedKRAsFor={approvedKRAsFor} notify={notify} />}
        {view === "cycles" && <CyclesAdmin users={users} cycles={cycles} setCycles={setCycles} onSaved={onSaved} onError={showError} notify={notify} onResetParticipant={resetParticipant} />}
        {view === "approvals" && <ApprovalsPage users={users} cycles={cycles} getRecord={getRecord} setRecord={setRecord} onSaved={onSaved} approvedKRAsFor={approvedKRAsFor} notify={notify} />}
        {view === "users" && <UsersAdmin users={users} setUsers={setUsers} onSaved={onSaved} onError={showError} onEditUser={editUser} cycles={cycles} onUploadKRA={uploadKRA} />}
        {view === "completed" && <CompletedPage me={me} cycles={cycles} getRecord={getRecord} approvedKRAsFor={approvedKRAsFor} />}
        {view === "mykra" && <ApprovedKRAPage me={me} cycles={cycles} records={records} />}
        {view === "inbox" && <InboxPage me={me} emails={emails} isHR={me.role === "hr"} />}
        {view === "reports" && <ReportsPage users={users} cycles={cycles} records={records} />}
        {view === "templates" && <EmailTemplatesPage templates={emailTemplates} onSave={saveTemplate} onReset={resetTemplate} />}
      </main>
    </div>
  );
}
